// SVG Icons — Based on provided asset pack
// Assets: arrow-path.svg, arrow-trending-up.svg, chart-pie.svg,
// chevron-down.svg, chevron-left.svg, chevron-right.svg, chevron-up-solid.svg,
// chevron-up.svg, cog-8-tooth.svg, cube-16-solid.svg, link-solid.svg,
// link.svg, search.svg, x-mark.svg

export const ArrowPathIcon = ({ size = 20, color = 'currentColor' }) => (
  // arrow-path.svg — circular arrows (refresh/cycle)
  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
    <path d="M4 12a8 8 0 018-8V2m0 0l-3 3m3-3l3 3" />
    <path d="M20 12a8 8 0 01-8 8v2m0 0l3-3m-3 3l-3-3" />
  </svg>
);

export const ArrowTrendingUpIcon = ({ size = 20, color = 'currentColor' }) => (
  // arrow-trending-up.svg — upward trend arrow
  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
    <polyline points="22 7 13.5 15.5 8.5 10.5 2 17" />
    <polyline points="16 7 22 7 22 13" />
  </svg>
);

export const ChartPieIcon = ({ size = 20, color = 'currentColor' }) => (
  // chart-pie.svg — pie chart
  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
    <path d="M21.21 15.89A10 10 0 118 2.83" />
    <path d="M22 12A10 10 0 0012 2v10z" />
  </svg>
);

export const ChevronDownIcon = ({ size = 20, color = 'currentColor' }) => (
  // chevron-down.svg
  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
    <polyline points="6 9 12 15 18 9" />
  </svg>
);

export const ChevronLeftIcon = ({ size = 20, color = 'currentColor' }) => (
  // chevron-left.svg
  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
    <polyline points="15 18 9 12 15 6" />
  </svg>
);

export const ChevronRightIcon = ({ size = 20, color = 'currentColor' }) => (
  // chevron-right.svg
  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
    <polyline points="9 18 15 12 9 6" />
  </svg>
);

export const ChevronUpSolidIcon = ({ size = 20, color = 'currentColor' }) => (
  // chevron-up-solid.svg — filled upward chevron
  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill={color} aria-hidden="true">
    <path fillRule="evenodd" clipRule="evenodd" d="M11.47 7.72a.75.75 0 011.06 0l7.5 7.5a.75.75 0 11-1.06 1.06L12 9.31l-6.97 6.97a.75.75 0 01-1.06-1.06l7.5-7.5z" />
  </svg>
);

export const ChevronUpIcon = ({ size = 20, color = 'currentColor' }) => (
  // chevron-up.svg
  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
    <polyline points="18 15 12 9 6 15" />
  </svg>
);

export const CogIcon = ({ size = 20, color = 'currentColor' }) => (
